const e={label:"Comune di Milano contributive quote 2025/2026 PDF",url:"https://www.comune.milano.it/documents/20118/1073744/2025-2026+Informazioni+quote+contributive+Nidi+e+Sezioni+Primavera.pdf/43e92661-59f6-c8aa-fd84-5a488891e4e0?version=1.0&t=1760368643025&download=true",verifiedAt:"Comune di Milano PDF dated 1 Jul 2025 for educational year 2025/2026",registrationFee:"EUR56.20",nido:{residentBands:[{iseeBand:"EUR0.00-EUR6,500.00",monthly:"free"},{iseeBand:"EUR6,500.01-EUR12,500.00",monthly:"EUR111.30"},{iseeBand:"EUR12,500.01-EUR27,000.00",monthly:"EUR250.60"},{iseeBand:"Above EUR27,000.00 or without ISEE",monthly:"EUR502.20"}],nonResidentMonthly:"EUR669.35"},sezionePrimavera:{residentBands:[{iseeBand:"EUR0.00-EUR6,500.00",monthly:"free"},{iseeBand:"EUR6,500.01-EUR12,500.00",monthly:"EUR55.65"},{iseeBand:"EUR12,500.01-EUR27,000.00",monthly:"EUR125.30"},{iseeBand:"Above EUR27,000.00 or without ISEE",monthly:"EUR251.10"}],nonResidentMonthly:"EUR334.68"},reductions:["50% of the assigned fee for low attendance of 5 days or fewer in the month and for December.","30% of the assigned fee for the second sibling, then EUR56.20/month for each sibling after the second.","50% of the assigned fee for a child in pre-adoptive foster care.","10% reduction on the total due for a single advance payment."]},t={milan:e},o=[{label:"Eurostat purchasing power parities",scope:"EU official country methodology",url:"https://ec.europa.eu/eurostat/web/purchasing-power-parities",observedAt:"Reviewed May 2026",statusLabel:"Active calibration input",freshness:"PPP hub now surfaces 25 Mar 2026 preliminary GDP-per-capita PPP news and 19 Jun 2025 household-consumption price levels for 2024.",note:"Official EU framework for purchasing power parities and comparative price levels. Used for country-level calibration and methodology checks, not direct city-rent inputs."},{label:"Finorum EU Cost of Living Pressure Index 2026",scope:"Independent country-level benchmark",url:"https://finorum.com/europe-cost-of-living-index-2026/",observedAt:"Published 12 Jan 2026",statusLabel:"Active calibration input",freshness:"Methodology page states it uses the latest available official data, primarily 2024 price and income series with 2023 housing-overburden data.",note:"Independent 2026 pressure index built from Eurostat housing, food, transport, disposable-income, and housing-overburden series. Used only as national pressure context."},{label:"EURES living and working conditions",scope:"EU official country context",url:"https://eures.europa.eu/living-and-working/living-and-working-conditions-europe_en",observedAt:"Reviewed May 2026",statusLabel:"Active methodology context",freshness:"Current EU guidance hub; used as a live policy-context check rather than as a numeric release series.",note:"Official EU cross-country living-and-working-conditions hub. Used to sanity-check national context rather than to populate city-level prices."},{label:"Numbeo methodology and live city pages",scope:"Crowd-sourced city benchmark",url:"https://www.numbeo.com/common/motivation_and_methodology.jsp",observedAt:"Reviewed May 2026",statusLabel:"Active city benchmark input",freshness:"Methodology reviewed in May 2026; the city pages used in this dashboard were refreshed in May 2026 and Numbeo says latest prices usually rely on data no older than 12 months.",note:"Explains Numbeo's hybrid methodology: crowd-sourced submissions plus manually gathered reputable-source inputs, with cost-of-living baskets centered on a four-person household. This remains the only complete third-party city dataset wired into section notes across the full roster."},{label:"Expatistan Europe cost-of-living index",scope:"Collaborative city price index",url:"https://www.expatistan.com/cost-of-living/index/europe",observedAt:"Reviewed May 2026",statusLabel:"Directional cross-check only",freshness:"The Europe index page is live but not versioned by release date; the same page showed user-submitted prices added minutes to hours ago during the May 2026 review.",note:"City prices are indexed to Prague = 100. Coverage across the target roster is partial, so it is still wired only into the Bilbao, Bologna, and Milan section notes where the city pages stayed current and did not carry the stronger low-data warnings seen on weaker pages. Follow-up checks on Lugo and Reggio Emilia did not clear the same bar."},{label:"Livingcost international cost-of-living calculator",scope:"Crowd-sourced city and country benchmark",url:"https://livingcost.org/cost",observedAt:"Updated 11 Mar 2026",statusLabel:"Directional cross-check only",freshness:"Livingcost publishes a moderate-lifestyle basket across 9,294 cities and 197 countries, but dashboard-city coverage is still partial.",note:"Useful as a second basket cross-check where city coverage exists, but its basket design differs from the family-with-infant budget model used in this dashboard. Current note-layer wiring remains limited to Bilbao, Bologna, and Milan and converts the page values back into EUR with the ECB reference rate used in this pass. The additional Lugo and Reggio Emilia checks returned no usable city pages."},{label:"N26 liveability index",scope:"Editorial city-ranking article",url:"https://n26.com/en-eu/blog/liveability-index",observedAt:"Rechecked May 2026",statusLabel:"Excluded after recheck",freshness:"The referenced public URL returned 404, and no current liveability index page was discoverable on the public N26 blog during this pass.",note:"Not used in current calibration. It stays documented here so the benchmark panel reflects that the source was rechecked and intentionally excluded instead of silently ignored."},{label:"TheGlobalEconomy World Bank cost-of-living index",scope:"Historical country-level benchmark",url:"https://www.theglobaleconomy.com/rankings/cost_of_living_wb/",observedAt:"Reviewed May 2026",statusLabel:"Historical reference only",freshness:"The public ranking page currently tops out at 2021 values from the World Bank International Comparison Program.",note:"Retained only as a historical country comparator. It is not used for current 2025/2026 calibration because the accessible public series stops at 2021."}];export{o as b,t as o};
